CREATE TABLE risk_model_domains
(
	id serial,
	risk_domain_id integer NOT NULL,
	risk_model_id integer NOT NULL,
	created_by_id integer NOT NULL,
	risk_management_owner_id integer NOT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_risk_model_domains PRIMARY KEY (id)
	, CONSTRAINT fk_risk_model_domains_to_risk_models FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_risk_model_domains_to_risk_domains FOREIGN KEY (risk_domain_id) REFERENCES risk_domains (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_risk_model_domains_to_users_created FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_risk_model_domains_to_users_rmowner FOREIGN KEY (risk_management_owner_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE UNIQUE INDEX ui_risk_model_domains ON risk_model_domains (risk_domain_id, risk_model_id);
CREATE INDEX i_risk_model_domains_risk_domain_id ON risk_model_domains (risk_domain_id);
CREATE INDEX i_risk_model_domains_risk_model_id ON risk_model_domains (risk_model_id);
CREATE INDEX i_risk_model_domains_created_by_id ON risk_model_domains (created_by_id);
CREATE INDEX i_risk_model_domains_management_owner_id ON risk_model_domains (risk_management_owner_id);
